#[test]
fn test_error_handling_invalid_syntax() {
    // Parsing invalid syntax should produce a tree with error nodes.
    let source = r#"function function function @@@ %%%"#;
    let config_json: serde_json::Value = serde_json::from_str(r#"{"language":"javascript"}"#).unwrap();
    let config = serde_json::from_value(config_json).unwrap();
    let _ = process(source, &config).expect("should succeed");
}

#[test]
fn test_error_handling_unknown_language() {
    // Loading a nonexistent language should produce an error.
    let source = r#""#;
    let config_json: serde_json::Value = serde_json::from_str(r#"{"language":"nonexistent_xyz"}"#).unwrap();
    let config = serde_json::from_value(config_json).unwrap();
    let result = process(source, &config);
    assert!(result.is_err(), "expected call to fail");
}

#[test]
fn test_error_process_empty_source() {
    // Process empty source code succeeds with zero metrics
    let source = r#""#;
    let config_json: serde_json::Value = serde_json::from_str(r#"{"language":"python"}"#).unwrap();
    let config = serde_json::from_value(config_json).unwrap();
    let result = process(source, &config).expect("should succeed");
    assert_eq!(result.metrics.total_lines, 0, "equals assertion failed");
}

#[test]
fn test_parse_empty_language() {
    // process() returns error with empty language name
    let source = r#"x = 1"#;
    let config_json: serde_json::Value = serde_json::from_str(r#"{"language":""}"#).unwrap();
    let config = serde_json::from_value(config_json).unwrap();
    let result = process(source, &config);
    assert!(result.is_err(), "expected call to fail");
}

#[test]
fn test_process_unknown_language() {
    // process() returns error when config language is unknown
    let source = r#"x = 1"#;
    let config_json: serde_json::Value = serde_json::from_str(r#"{"language":"nonexistent_xyz"}"#).unwrap();
    let config = serde_json::from_value(config_json).unwrap();
    let result = process(source, &config);
    assert!(result.is_err(), "expected call to fail");
}
